const data = $input.all();

let totalSales = "";
let totalOrders = "";
let avgOrderValue = "";
let topProduct = "";
let regionSales = "";
let productSales = "";
let dailySales = "";

// Total Sales & Orders
if (data[0]) {
  totalSales = data[0].json.Total_Sales;
  totalOrders = data[0].json.Total_Orders;
}

// Average Order Value
if (data[1]) {
  avgOrderValue = Number(data[1].json.Average_Order_Value).toFixed(2);
}

// Top Product
if (data[2]) {
  topProduct = `${data[2].json.Product} (₹${data[2].json.Total_Sales})`;
}

// Region-wise Sales
if (data[3]) {
  regionSales = data
    .filter(item => item.json.Region)
    .map(item => `• ${item.json.Region}: ₹${item.json.Total_Sales}`)
    .join("\n");
}

// Product-wise Sales
productSales = data
  .filter(item => item.json.Product && item.json.Revenue)
  .map(item =>
    `• ${item.json.Product}
     Orders: ${item.json.Orders}
     Units Sold: ${item.json.Units_Sold}
     Revenue: ₹${item.json.Revenue}`
  )
  .join("\n\n");

// Daily Sales
dailySales = data
  .filter(item => item.json.Date)
  .map(item => `• ${item.json.Date}: ₹${item.json.Daily_Sales}`)
  .join("\n");

return [{
  json: {
    report: `📊 SALES PERFORMANCE REPORT

══════════════════════════════

💰 Total Sales: ₹${totalSales}
🛒 Total Orders: ${totalOrders}
💵 Average Order Value: ₹${avgOrderValue}

🏆 Top Selling Product:
${topProduct}

══════════════════════════════

🌍 REGION-WISE SALES

${regionSales}

══════════════════════════════

📦 PRODUCT-WISE SALES

${productSales}

══════════════════════════════

📅 DAILY SALES

${dailySales}

══════════════════════════════

✅ Report Generated Automatically by n8n
📌 Data Source: MySQL
`
  }
}];
